const EMAIL_LOGO_PNG_BASE64 = "";

const EMAIL_HERO_V1_PNG_BASE64 = "";

const EMAIL_HERO_V2_PNG_BASE64 = "";

function decodeBase64(value: string): Uint8Array {
  const binary = atob(value);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i += 1) {
    bytes[i] = binary.charCodeAt(i);
  }
  return bytes;
}

export function getEmailLogoBytes(): Uint8Array {
  return decodeBase64(EMAIL_LOGO_PNG_BASE64);
}

export function getEmailHeroV1Bytes(): Uint8Array {
  return decodeBase64(EMAIL_HERO_V1_PNG_BASE64);
}

export function getEmailHeroV2Bytes(): Uint8Array {
  return decodeBase64(EMAIL_HERO_V2_PNG_BASE64);
}
